import AsyncStorage from '@react-native-async-storage/async-storage';
import { useState, useEffect } from 'react';

let _lang = 'es';
let _listeners = [];

export const getLang = () => _lang;
export const setLang = async (lang) => {
  _lang = lang;
  await AsyncStorage.setItem('perfil_idioma', lang);
  _listeners.forEach(fn => fn(lang));
};
export const onLangChange = (fn) => { _listeners.push(fn); return () => { _listeners = _listeners.filter(f => f !== fn); }; };

export const initLang = async () => {
  const saved = await AsyncStorage.getItem('perfil_idioma');
  if (saved && saved !== _lang) {
    _lang = saved;
    _listeners.forEach(fn => fn(_lang));
  }
  return _lang;
};

