  // Portafolio (9 items)
  cu_portafolio_1: { es: 'Agregá activos: botón + arriba a la derecha del header.', en: 'Add assets: + button at the top right of the header.', pt: 'Adicionar ativos: botão + no canto superior direito do cabeçalho.', zh: '添加资产：标题栏右上角的 + 按钮。', fr: 'Ajouter des actifs : bouton + en haut à droite de l\'en-tête.', it: 'Aggiungi asset: pulsante + in alto a destra dell\'intestazione.', hi: 'एसेट जोड़ें: हेडर के ऊपरी दाएं + बटन।', ar: 'إضافة أصول: زر + أعلى يمين الرأس.' },
  cu_portafolio_2: { es: 'Valor total y moneda: tocá el badge $ para ciclar entre USD / USDT / BTC. PnL del período al lado.', en: 'Total value and currency: tap the $ badge to cycle USD / USDT / BTC. Period PnL next to it.', pt: 'Valor total e moeda: toque no badge $ para alternar USD / USDT / BTC. PnL do período ao lado.', zh: '总价值与货币：点击 $ 徽章在 USD / USDT / BTC 间切换。旁边为周期盈亏。', fr: 'Valeur totale et devise : appuyez sur le badge $ pour basculer USD / USDT / BTC. PnL de la période à côté.', it: 'Valore totale e valuta: tocca il badge $ per ciclare USD / USDT / BTC. PnL del periodo a fianco.', hi: 'कुल मूल्य और मुद्रा: USD / USDT / BTC के बीच स्विच करने के लिए $ बैज पर टैप करें। साथ में अवधि का PnL।', ar: 'القيمة الإجمالية والعملة: اضغط على شارة $ للتنقل بين USD / USDT / BTC. الربح/الخسارة للفترة بجانبها.' },
  cu_portafolio_3: { es: 'Períodos: 24h / 7d / 1m / 3m / 1y debajo del valor total.', en: 'Periods: 24h / 7d / 1m / 3m / 1y below the total value.', pt: 'Períodos: 24h / 7d / 1m / 3m / 1y abaixo do valor total.', zh: '周期：24h / 7d / 1m / 3m / 1y 显示在总价值下方。', fr: 'Périodes : 24h / 7j / 1m / 3m / 1a sous la valeur totale.', it: 'Periodi: 24h / 7g / 1m / 3m / 1a sotto il valore totale.', hi: 'अवधि: कुल मूल्य के नीचे 24h / 7d / 1m / 3m / 1y।', ar: 'الفترات: 24س / 7ي / 1ش / 3ش / 1س أسفل القيمة الإجمالية.' },
  cu_portafolio_4: { es: 'Termómetro de riesgo: ALCISTA / BAJISTA / ALTA-CONV-IA / SIN-SEÑAL según señales IA.', en: 'Risk thermometer: BULLISH / BEARISH / HIGH-CONV-AI / NO-SIGNAL based on AI signals.', pt: 'Termômetro de risco: ALTA / BAIXA / ALTA-CONV-IA / SEM-SINAL conforme sinais de IA.', zh: '风险温度计：根据 AI 信号显示 多头 / 空头 / 高确信度-AI / 无信号。', fr: 'Thermomètre de risque : HAUSSIER / BAISSIER / HAUTE-CONV-IA / SANS-SIGNAL selon les signaux IA.', it: 'Termometro di rischio: RIALZISTA / RIBASSISTA / ALTA-CONV-IA / SENZA-SEGNALE secondo i segnali IA.', hi: 'जोखिम थर्मामीटर: AI सिग्नल के अनुसार तेजी / मंदी / उच्च-कन्व-AI / बिना-सिग्नल।', ar: 'مقياس المخاطر: صاعد / هابط / عالي-الثقة-AI / بدون-إشارة وفقًا لإشارات الذكاء الاصطناعي.' },
  cu_portafolio_5: { es: 'TAP en activo: detalle con precio, PnL, señal IA, simulador, máx/mín 52 sem y motivos.', en: 'TAP on asset: details with price, PnL, AI signal, simulator, 52w high/low and reasons.', pt: 'TAP no ativo: detalhe com preço, PnL, sinal IA, simulador, máx/mín 52 sem e motivos.', zh: '点击资产：包含价格、盈亏、AI 信号、模拟器、52 周最高/最低与原因的详细信息。', fr: 'TAP sur l\'actif : détails avec prix, PnL, signal IA, simulateur, max/min 52 sem et motifs.', it: 'TAP sull\'asset: dettaglio con prezzo, PnL, segnale IA, simulatore, max/min 52 sett e motivi.', hi: 'एसेट पर टैप: मूल्य, PnL, AI सिग्नल, सिमुलेटर, 52 हफ्ते का उच्च/निम्न और कारण।', ar: 'اضغط على الأصل: تفاصيل بالسعر، الربح/الخسارة، إشارة AI، المحاكي، أعلى/أدنى 52 أسبوعًا والأسباب.' },
  cu_portafolio_6: { es: 'Crear alerta desde el row: ícono campana en la fila de cada activo.', en: 'Create alert from the row: bell icon on each asset row.', pt: 'Criar alerta na linha: ícone de sino na linha de cada ativo.', zh: '从行内创建提醒：每个资产行上的铃铛图标。', fr: 'Créer une alerte depuis la ligne : icône de cloche sur la ligne de chaque actif.', it: 'Crea avviso dalla riga: icona campana nella riga di ogni asset.', hi: 'पंक्ति से अलर्ट बनाएं: प्रत्येक एसेट पंक्ति पर घंटी आइकन।', ar: 'إنشاء تنبيه من الصف: أيقونة الجرس في صف كل أصل.' },
