  cu_alertas_5: { es: 'Alertas Precio: 3 toggles (variación / máx-mín / RSI extremo).', en: 'Price Alerts: 3 toggles (variation / high-low / extreme RSI).', pt: 'Alertas Preço: 3 toggles (variação / máx-mín / RSI extremo).', zh: '价格提醒：3 个开关（变动 / 最高-最低 / 极端 RSI）。', fr: 'Alertes Prix : 3 bascules (variation / max-min / RSI extrême).', it: 'Avvisi Prezzo: 3 toggle (variazione / max-min / RSI estremo).', hi: 'मूल्य अलर्ट: 3 टॉगल (परिवर्तन / उच्च-निम्न / चरम RSI)।', ar: 'تنبيهات السعر: 3 مفاتيح (تغير / أعلى-أدنى / RSI متطرف).' },
  cu_alertas_6: { es: 'Alertas Eventos: 5 toggles (FOMC / CPI / apertura / earnings / GDELT).', en: 'Event Alerts: 5 toggles (FOMC / CPI / open / earnings / GDELT).', pt: 'Alertas Eventos: 5 toggles (FOMC / CPI / abertura / earnings / GDELT).', zh: '事件提醒：5 个开关（FOMC / CPI / 开盘 / 财报 / GDELT）。', fr: 'Alertes Événements : 5 bascules (FOMC / CPI / ouverture / earnings / GDELT).', it: 'Avvisi Eventi: 5 toggle (FOMC / CPI / apertura / earnings / GDELT).', hi: 'इवेंट अलर्ट: 5 टॉगल (FOMC / CPI / ओपन / अर्निंग्स / GDELT)।', ar: 'تنبيهات الأحداث: 5 مفاتيح (FOMC / CPI / الافتتاح / الأرباح / GDELT).' },
  cu_alertas_7: { es: 'Historial: tap en la campana del header → pantalla "Mis Alertas" con historial completo.', en: 'History: tap the header bell → "My Alerts" screen with full history.', pt: 'Histórico: toque no sino do cabeçalho → tela "Minhas Alertas" com histórico completo.', zh: '历史：点击标题栏铃铛 → 含完整历史的"我的提醒"屏幕。', fr: 'Historique : appuyez sur la cloche de l\'en-tête → écran "Mes Alertes" avec historique complet.', it: 'Cronologia: tocca la campana dell\'intestazione → schermata "I miei avvisi" con cronologia completa.', hi: 'इतिहास: हेडर की घंटी पर टैप करें → पूर्ण इतिहास के साथ "मेरे अलर्ट" स्क्रीन।', ar: 'السجل: اضغط على جرس الرأس → شاشة "تنبيهاتي" بالسجل الكامل.' },

  // Perfil (6 items)
  cu_perfil_1: { es: 'Tema: cambiá entre modo oscuro y claro en Preferencias.', en: 'Theme: switch between dark and light mode in Preferences.', pt: 'Tema: alterne entre modo escuro e claro em Preferências.', zh: '主题：在偏好设置中切换深色和浅色模式。', fr: 'Thème : basculer entre mode sombre et clair dans Préférences.', it: 'Tema: alterna tra modalità scura e chiara in Preferenze.', hi: 'थीम: प्राथमिकताओं में डार्क और लाइट मोड के बीच स्विच करें।', ar: 'السمة: التبديل بين الوضع الداكن والفاتح في التفضيلات.' },
  cu_perfil_2: { es: 'Idioma: 8 idiomas disponibles en Preferencias (es / en / pt / zh / fr / it / hi / ar).', en: 'Language: 8 languages available in Preferences (es / en / pt / zh / fr / it / hi / ar).', pt: 'Idioma: 8 idiomas disponíveis em Preferências (es / en / pt / zh / fr / it / hi / ar).', zh: '语言：偏好设置中提供 8 种语言（es / en / pt / zh / fr / it / hi / ar）。', fr: 'Langue : 8 langues disponibles dans Préférences (es / en / pt / zh / fr / it / hi / ar).', it: 'Lingua: 8 lingue disponibili in Preferenze (es / en / pt / zh / fr / it / hi / ar).', hi: 'भाषा: प्राथमिकताओं में 8 भाषाएँ उपलब्ध (es / en / pt / zh / fr / it / hi / ar)।', ar: 'اللغة: 8 لغات متاحة في التفضيلات (es / en / pt / zh / fr / it / hi / ar).' },
  cu_perfil_3: { es: 'Seguridad: activá FaceID o huella en Seguridad. 2FA próximamente.', en: 'Security: enable FaceID or fingerprint in Security. 2FA coming soon.', pt: 'Segurança: ative FaceID ou impressão digital em Segurança. 2FA em breve.', zh: '安全：在"安全"中启用 FaceID 或指纹。2FA 即将推出。', fr: 'Sécurité : activez FaceID ou empreinte dans Sécurité. 2FA bientôt.', it: 'Sicurezza: attiva FaceID o impronta in Sicurezza. 2FA prossimamente.', hi: 'सुरक्षा: सुरक्षा में FaceID या फ़िंगरप्रिंट सक्षम करें। 2FA जल्द ही।', ar: 'الأمان: قم بتفعيل FaceID أو البصمة في الأمان. 2FA قريبًا.' },
  cu_perfil_4: { es: 'Notificaciones: push del SO, resumen diario, novedades de la app.', en: 'Notifications: OS push, daily summary, app news.', pt: 'Notificações: push do SO, resumo diário, novidades do app.', zh: '通知：系统推送、每日摘要、应用新闻。', fr: 'Notifications : push OS, résumé quotidien, actualités de l\'app.', it: 'Notifiche: push SO, riepilogo giornaliero, novità dell\'app.', hi: 'सूचनाएँ: OS पुश, दैनिक सारांश, ऐप समाचार।', ar: 'الإشعارات: Push للنظام، الملخص اليومي، أخبار التطبيق.' },
  cu_perfil_5: { es: 'Soporte: FAQ, calificar la app, contacto y redes sociales.', en: 'Support: FAQ, rate the app, contact and social media.', pt: 'Suporte: FAQ, avaliar o app, contato e redes sociais.', zh: '支持：常见问题、为应用评分、联系方式和社交媒体。', fr: 'Support : FAQ, noter l\'app, contact et réseaux sociaux.', it: 'Supporto: FAQ, valuta l\'app, contatto e social media.', hi: 'सहायता: FAQ, ऐप को रेट करें, संपर्क और सोशल मीडिया।', ar: 'الدعم: الأسئلة الشائعة، تقييم التطبيق، الاتصال ووسائل التواصل الاجتماعي.' },
  cu_perfil_6: { es: 'Cuenta: cerrar sesión o eliminar cuenta en la sección inferior.', en: 'Account: log out or delete account in the bottom section.', pt: 'Conta: sair ou excluir conta na seção inferior.', zh: '账户：在底部部分注销或删除账户。', fr: 'Compte : se déconnecter ou supprimer le compte dans la section inférieure.', it: 'Account: disconnettiti o elimina account nella sezione inferiore.', hi: 'खाता: नीचे के अनुभाग में लॉग आउट करें या खाता हटाएं।', ar: 'الحساب: تسجيل الخروج أو حذف الحساب في القسم السفلي.' },

