  popup_telegram_intro: { es: 'Para recibir alertas en tu Telegram, conectá tu cuenta al bot oficial de Cobrex:', en: 'To receive alerts on your Telegram, connect your account to the official Cobrex bot:', pt: 'Para receber alertas no seu Telegram, conecte sua conta ao bot oficial da Cobrex:', zh: '要在您的Telegram上接收提醒,请将您的账户连接到Cobrex官方机器人:' , fr: 'Pour recevoir des alertes sur votre Telegram, connectez votre compte au bot officiel Cobrex :', it: 'Per ricevere avvisi sul tuo Telegram, connetti il tuo account al bot ufficiale di Cobrex:', hi: 'अपने Telegram पर अलर्ट पाने के लिए, अपने खाते को Cobrex के आधिकारिक बॉट से जोड़ें:', ar: 'لاستلام التنبيهات على Telegram، قم بربط حسابك ببوت Cobrex الرسمي:' },
  popup_telegram_paso1: { es: 'Tocá el botón abajo → se abre @Aurexalertas_bot en tu app de Telegram.', en: 'Tap the button below → @Aurexalertas_bot opens in your Telegram app.', pt: 'Toque no botão abaixo → @Aurexalertas_bot abre no seu app Telegram.', zh: '点击下方按钮 → 在您的Telegram应用中打开 @Aurexalertas_bot。' , fr: 'Touchez le bouton ci-dessous → @Aurexalertas_bot s\'ouvre dans votre app Telegram.', it: 'Tocca il pulsante sotto → @Aurexalertas_bot si apre nella tua app Telegram.', hi: 'नीचे बटन दबाएँ → आपके Telegram ऐप में @Aurexalertas_bot खुलेगा।', ar: 'انقر على الزر أدناه ← يُفتح @Aurexalertas_bot في تطبيق Telegram.' },
  popup_telegram_paso2: { es: 'En el bot, tocá Iniciar (o escribí /start).', en: 'In the bot, tap Start (or type /start).', pt: 'No bot, toque em Iniciar (ou digite /start).', zh: '在机器人中,点击"开始"(或输入 /start)。' , fr: 'Dans le bot, touchez Démarrer (ou tapez /start).', it: 'Nel bot, tocca Avvia (o scrivi /start).', hi: 'बॉट में, प्रारंभ दबाएँ (या /start टाइप करें)।', ar: 'في البوت، اضغط بدء (أو اكتب /start).' },
  popup_telegram_paso3: { es: 'Listo → vas a recibir cada alerta en tu Telegram personal.', en: 'Done → you\'ll receive each alert on your personal Telegram.', pt: 'Pronto → você receberá cada alerta no seu Telegram pessoal.', zh: '完成 → 您将在您的个人Telegram上接收每条提醒。' , fr: 'Prêt → vous recevrez chaque alerte sur votre Telegram personnel.', it: 'Fatto → riceverai ogni avviso sul tuo Telegram personale.', hi: 'हो गया → आप प्रत्येक अलर्ट अपने व्यक्तिगत Telegram पर प्राप्त करेंगे।', ar: 'تم → ستتلقى كل تنبيه على Telegram الشخصي.' },
  popup_telegram_cta: { es: 'Abrir bot @Aurexalertas', en: 'Open bot @Aurexalertas', pt: 'Abrir bot @Aurexalertas', zh: '打开机器人 @Aurexalertas' , fr: 'Ouvrir le bot @Aurexalertas', it: 'Apri bot @Aurexalertas', hi: 'बॉट @Aurexalertas खोलें', ar: 'فتح بوت @Aurexalertas' },
  popup_telegram_foot: { es: 'Solo se hace una vez. Después podés desactivarlo desde el switch.', en: 'Only done once. You can disable it later from the switch.', pt: 'Apenas uma vez. Depois você pode desativar pelo switch.', zh: '只需操作一次。之后您可以从开关停用。' , fr: 'Une seule fois. Vous pouvez le désactiver depuis l\'interrupteur.', it: 'Solo una volta. Puoi disattivarlo dall\'interruttore.', hi: 'एक बार ही करना है। बाद में आप स्विच से बंद कर सकते हैं।', ar: 'مرة واحدة فقط. يمكنك إيقافه لاحقًا من المفتاح.' },

