export const t = (key) => {
  const entry = T[key];
  if (!entry) return key;
  return entry[_lang] || entry.es || key;
};

// Helper para traducir el campo "tipo" de activos (valores que vienen del data)
export const translateTipo = (tipo) => {
  if (!tipo) return '';
  const norm = String(tipo).toLowerCase().replace(/\s+/g, '_');
  const map = {
    cripto: 'tipo_cripto', crypto: 'tipo_cripto',
    accion: 'tipo_accion', stock: 'tipo_accion',
    etf: 'tipo_etf',
    bono: 'tipo_bono', bond: 'tipo_bono',
    metal: 'tipo_metal',
    materia_prima: 'tipo_materia_prima',
    divisa: 'tipo_divisa', forex: 'tipo_divisa',
    commodity: 'tipo_commodity', commodities: 'tipo_commodity',
    stable: 'tipo_stable',
    futuro: 'tipo_futuro', future: 'tipo_futuro',
  };
  const key = map[norm];
  return key ? t(key) : tipo;
};

// Hook reactivo: re-renderiza el componente cuando cambia el idioma
export const useT = () => {
  const [, setTick] = useState(0);
  useEffect(() => {
    const unsub = onLangChange(() => setTick(x => x + 1));
    return unsub;
  }, []);
  return t;
};

export default t;
